 51→// Validator validates a JWT token string and returns parsed claims.
 52→type Validator interface {
 53→	Validate(tokenString string) (*Claims, error)
 54→}
 55→
 56→// HMACValidator validates HS256 tokens using a shared secret.
 57→type HMACValidator struct {
 58→	secret     []byte
 59→	parserOpts []jwt.ParserOption
 60→}
 61→
 62→// NewHMACValidator creates a Validator using HS256 with the provided secret.
 63→func NewHMACValidator(secret string, opts ...jwt.ParserOption) *HMACValidator {
 64→	return &HMACValidator{
 65→		secret:     []byte(secret),
 66→		parserOpts: opts,
 67→	}
 68→}
 69→
 70→// Validate parses and validates an HS256 JWT token string.
 71→func (v *HMACValidator) Validate(tokenString string) (*Claims, error) {
 72→	claims := &Claims{}
 73→	token, err := jwt.ParseWithClaims(tokenString, claims, func(t *jwt.Token) (any, error) {
 74→		if _, ok := t.Method.(*jwt.SigningMethodHMAC); !ok {
 75→			return nil, fmt.Errorf("auth: unexpected signing method: %v", t.Header["alg"])
 76→		}
 77→		return v.secret, nil
 78→	}, v.parserOpts...)
 79→	if err != nil {
 80→		return nil, fmt.Errorf("auth: token validation failed: %w", err)
 81→	}
 82→	if !token.Valid {
 83→		return nil, errors.New("auth: token is not valid")
 84→	}
 85→	return claims, nil
 86→}
 87→
 88→// RSAValidator validates RS256 tokens using an RSA public key.
 89→type RSAValidator struct {
 90→	publicKey  *rsa.PublicKey
 91→	parserOpts []jwt.ParserOption
 92→}
 93→
 94→// NewRSAValidator creates a Validator using RS256 with the provided PEM public key.
 95→func NewRSAValidator(pemPublicKey string, opts ...jwt.ParserOption) (*RSAValidator, error) {
 96→	key, err := jwt.ParseRSAPublicKeyFromPEM([]byte(pemPublicKey))
 97→	if err != nil {
 98→		return nil, fmt.Errorf("auth: failed to parse RSA public key: %w", err)
 99→	}
100→	return &RSAValidator{
101→		publicKey:  key,
102→		parserOpts: opts,
103→	}, nil
104→}
105→
106→// Validate parses and validates an RS256 JWT token string.
107→func (v *RSAValidator) Validate(tokenString string) (*Claims, error) {
108→	claims := &Claims{}
109→	token, err := jwt.ParseWithClaims(tokenString, claims, func(t *jwt.Token) (any, error) {
110→		if _, ok := t.Method.(*jwt.SigningMethodRSA); !ok {
111→			return nil, fmt.Errorf("auth: unexpected signing method: %v", t.Header["alg"])
112→		}
113→		return v.publicKey, nil
114→	}, v.parserOpts...)
115→	if err != nil {
116→		return nil, fmt.Errorf("auth: token validation failed: %w", err)
117→	}
118→	if !token.Valid {
119→		return nil, errors.New("auth: token is not valid")
120→	}
121→	return claims, nil
122→}
